
'use client'

import Sidebar from './Sidebar'
import { logout } from '@/app/actions/auth'
import { usePathname } from 'next/navigation'

export default function LayoutWrapper({
  children
}: {
  children: React.ReactNode
}) {
  const pathname = usePathname()
  // Show sidebar on all pages except login page ('/')
  const showSidebar = pathname !== '/'

  if (!showSidebar) {
    return <>{children}</>
  }

  return (
    <div className="flex">
      <Sidebar />
      <div className="flex-1 ml-64 min-h-screen bg-gray-50 flex flex-col">
        {/* Header with Logout */}
        <header className="bg-white shadow-sm h-16 flex items-center justify-between px-8 sticky top-0 z-10 print:hidden">
          <div className="font-semibold text-gray-700 uppercase tracking-wider">
            {pathname.split('/').filter(Boolean).join(' / ') || 'Dashboard'}
          </div>
          <button
            onClick={() => logout()}
            className="text-sm font-medium text-red-600 hover:text-red-800 transition-colors flex items-center gap-2"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M3 3a1 1 0 00-1 1v12a1 1 0 102 0V4a1 1 0 00-1-1zm10.293 9.293a1 1 0 001.414 1.414l3-3a1 1 0 000-1.414l-3-3a1 1 0 10-1.414 1.414L14.586 9H7a1 1 0 100 2h7.586l-1.293 1.293z" clipRule="evenodd" />
            </svg>
            Logout
          </button>
        </header>
        
        <main className="p-8 text-gray-800 print:p-0 print:bg-white flex-1">
          {children}
        </main>
      </div>
    </div>
  )
}
